// ==================== 查询函数 ====================

/** 获取所有学校 */
function getAllSchools() {
  return ALL_SCHOOLS.map(expandSchool);
}

/** 按层次筛选 */
function getSchoolsByLevel(level) {
  return ALL_SCHOOLS.filter(function(s) { return s.l === level; }).map(expandSchool);
}

/** 按省份筛选 */
function getSchoolsByProvince(province) {
  return ALL_SCHOOLS.filter(function(s) { return s.p === province; }).map(expandSchool);
}

/** 按类型筛选 */
function getSchoolsByType(type) {
  return ALL_SCHOOLS.filter(function(s) { return s.t === type; }).map(expandSchool);
}

/** 模糊搜索 */
function searchSchools(keyword) {
  if (!keyword || !keyword.trim()) return ALL_SCHOOLS.map(expandSchool);
  var q = keyword.trim().toLowerCase();
  return ALL_SCHOOLS.filter(function(s) {
    if (s.n.toLowerCase().indexOf(q) !== -1) return true;
    if (s.p.toLowerCase().indexOf(q) !== -1) return true;
    if (s.c.toLowerCase().indexOf(q) !== -1) return true;
    if (s.t.toLowerCase().indexOf(q) !== -1) return true;
    return false;
  }).map(expandSchool);
}

/** 精确查询 */
function getSchoolByName(name) {
  for (var i = 0; i < ALL_SCHOOLS.length; i++) {
    if (ALL_SCHOOLS[i].n === name) return expandSchool(ALL_SCHOOLS[i]);
  }
  return null;
}

/** 按标签搜索 */
function getSchoolsByTag(tag) {
  return ALL_SCHOOLS.filter(function(s) {
    return s.tg && s.tg.indexOf(tag) !== -1;
  }).map(expandSchool);
}

/** 获取本科排行榜 */
function getUndergraduateRankings() {
  return ALL_SCHOOLS.filter(function(s) { return s.l === '本科' && s.r; })
    .sort(function(a, b) { return (a.r || 9999) - (b.r || 9999); })
    .map(expandSchool);
}

/** 获取专科排行榜（双高计划优先） */
function getVocationalRankings() {
  return ALL_SCHOOLS.filter(function(s) { return s.l === '专科'; })
    .sort(function(a, b) {
      if (a.vr && b.vr) return a.vr - b.vr;
      if (a.vr) return -1;
      if (b.vr) return 1;
      return a.n.localeCompare(b.n, 'zh');
    })
    .map(expandSchool);
}

/** 扩展学校数据（短字段→长字段） */
function expandSchool(s) {
  return {
    name: s.n,
    province: s.p,
    city: s.c,
    type: s.t,
    level: s.l,
    department: s.d,
    isPublic: s.pb,
    ranking: s.r || 0,
    score: s.s || 0,
    tags: s.tg || [],
    vocRank: s.vr || 0,
    shuanggaoLevel: s.sl || ''
  };
}

/** 获取所有省份列表 */
function getSchoolProvinces() {
  var provinces = [];
  for (var i = 0; i < ALL_SCHOOLS.length; i++) {
    var p = ALL_SCHOOLS[i].p;
    if (provinces.indexOf(p) === -1) provinces.push(p);
  }
  return provinces.sort(function(a, b) {
    return a.localeCompare(b, 'zh');
  });
}

/** 获取所有学校类型 */
function getSchoolTypes() {
  var types = [];
  for (var i = 0; i < ALL_SCHOOLS.length; i++) {
    var t = ALL_SCHOOLS[i].t;
    if (types.indexOf(t) === -1) types.push(t);
  }
  return types.sort();
}

/** 获取统计信息 */
function getSchoolStats() {
  var undergrad = 0, vocational = 0;
  var publicCount = 0, privateCount = 0;
  for (var i = 0; i < ALL_SCHOOLS.length; i++) {
    if (ALL_SCHOOLS[i].l === '本科') undergrad++;
    else vocational++;
    if (ALL_SCHOOLS[i].pb) publicCount++;
    else privateCount++;
  }
  return {
    total: ALL_SCHOOLS.length,
    undergraduate: undergrad,
    vocational: vocational,
    public: publicCount,
    private: privateCount
  };
}

console.log('[schools-db] 已加载 ' + ALL_SCHOOLS.length + ' 所学校（本科' + getSchoolStats().undergraduate + '所 + 专科' + getSchoolStats().vocational + '所）');
